class Solution:
    def reformatNumber(self, number: str) -> str:
        number = ''.join(filter(str.isdigit, number))
        result = []
        while number:
            if len(number) >= 3:
                result.append(number[:3])
                number = number[3:]
            else:
                result.append(number)
                break
        return '-'.join(result)
